#!/usr/bin/env python3
"""Dream Abroad - Update v7: Client Edit + Room/Bed Linking"""
import base64, os, sys

PROJECT = os.path.expanduser("~/Desktop/dream-abroad")
if not os.path.isdir(PROJECT):
    print("ERRO: Pasta ~/Desktop/dream-abroad nao encontrada")
    sys.exit(1)

files = {}
files["frontend/src/pages/Clients.tsx"] = ""
files["frontend/src/pages/ClientProfile.tsx"] = ""
files["backend/routers/clients.py"] = ""

for rel, b64 in files.items():
    full = os.path.join(PROJECT, rel)
    os.makedirs(os.path.dirname(full), exist_ok=True)
    with open(full, "wb") as f:
        f.write(base64.b64decode(b64))
    print(f"  OK: {rel}")

# Fix api.ts baseURL
api_path = os.path.join(PROJECT, "frontend/src/services/api.ts")
if os.path.exists(api_path):
    with open(api_path, "r") as f:
        content = f.read()
    if "http://localhost:8000" in content:
        content = content.replace("http://localhost:8000", "")
        with open(api_path, "w") as f:
            f.write(content)
        print("  OK: api.ts baseURL corrigido")

print()
print("=" * 50)
print("Update v7 aplicado com sucesso!")
print("=" * 50)
print()
print("O que mudou:")
print("  1. Clientes: botao Editar na tabela (icone lapis)")
print("  2. Clientes: modal de edicao com quarto/cama")
print("  3. Perfil Cliente: secao Acomodacao com botao Alterar")
print("  4. Perfil Cliente: botao Editar no topo")
print("  5. Backend: room_id/bed_id no endpoint profile")
print()
print("Reinicie o backend:")
print("  cd ~/Desktop/dream-abroad/backend")
print("  source venv/bin/activate && uvicorn main:app --reload")